def predict(triples: list[Triple]) -> str:
    """Generate a natural language sentence from a list of triples."""
    if not triples:
        return ""

    def clean_subject(subject: str) -> str:
        """Remove '(comicsCharacter)' suffix from subject names."""
        return subject.replace(" (comicsCharacter)", "").replace("(comicsCharacter)", "")

    def clean_object(obj: str) -> str:
        """Remove surrounding quotes from object values."""
        if obj and ((obj.startswith('"') and obj.endswith('"')) or (obj.startswith("'") and obj.endswith("'"))):
            return obj[1:-1]
        return obj

    # Group triples by subject for complex sentence building
    subject_triples = {}
    for t in triples:
        subject = clean_subject(t.subject)
        if subject not in subject_triples:
            subject_triples[subject] = []
        subject_triples[subject].append((t.predicate, clean_object(t.object)))

    # Mapping predicates to phrase generators with better grammar
    def alt_name(s, o): return f"also known as {o}"
    def creator(s, o): return f"was created by {o}"
    def full_name(s, o): return f"whose full name is {o}"
    def founded_by(s, o): return f"was founded by {o}"
    def key_person(s, o): return f"has {o} as a key person"
    def city(s, o): return f"located in {o}"
    def product(s, o): return f"produces {o}"
    def last_aired(s, o): return f"last aired on {o}"
    def starring(s, o): return f"stars {o}"
    def first_appearance(s, o): return f"first appeared in the film {o}"
    def voice(s, o): return f"voiced by {o}"
    def distributor(s, o): return f"was distributed by {o}"
    def birth_place(s, o): return f"was born in {o}"
    def nationality(s, o):
        # Handle nationality more naturally
        o_lower = o.lower()
        if o_lower == "americans" or o_lower == "united states":
            return "American"
        elif o_lower == "canadians":
            return "Canadian"
        elif o_lower == "british":
            return "British"
        elif o_lower == "united kingdom":
            return "British"
        elif o.endswith("s") and o not in ["US", "UK"]:
            return o[:-1]
        else:
            return o
    def award(s, o): return f"received the {o}"
    def broadcasted_by(s, o): return f"was broadcasted by {o}"
    def first_aired(s, o): return f"first aired on {o}"
    def series(s, o): return f"part of the series {o}"
    def child(s, o): return f"has a child named {o}"

    phrase_funcs = {
        "alternativeName": alt_name,
        "creator": creator,
        "fullName": full_name,
        "foundedBy": founded_by,
        "keyPerson": key_person,
        "city": city,
        "product": product,
        "lastAired": last_aired,
        "starring": starring,
        "firstAppearanceInFilm": first_appearance,
        "voice": voice,
        "distributor": distributor,
        "birthPlace": birth_place,
        "nationality": nationality,
        "award": award,
        "broadcastedBy": broadcasted_by,
        "firstAired": first_aired,
        "series": series,
        "child": child,
    }

    # Build complex sentence from ALL triples - one unified sentence
    all_clauses = []

    # Track which subjects we've processed
    processed_subjects = set()

    for subject, subject_trips in subject_triples.items():
        # Sort triples by priority (more important info first)
        priority = ["creator", "fullName", "alternativeName", "nationality", "birthPlace", "award", "child", "series", "starring", "voice", "distributor", "broadcastedBy", "city", "product", "lastAired", "firstAired", "firstAppearanceInFilm", "foundedBy", "keyPerson", "product", "award", "child"]
        sorted_trips = sorted(subject_trips, key=lambda t: priority.index(t[0]) if t[0] in priority else len(priority))

        # Group by predicate to handle multiple values (e.g., multiple creators)
        pred_to_objs = {}
        for pred, obj in sorted_trips:
            if pred not in pred_to_objs:
                pred_to_objs[pred] = []
            pred_to_objs[pred].append(obj)

        # Create unique predicate entries with combined objects
        unique_trips = []
        for pred in sorted(pred_to_objs.keys()):
            objs = pred_to_objs[pred]
            if len(objs) > 1:
                # Combine multiple objects with "and"
                combined = " and ".join(objs)
                unique_trips.append((pred, combined))
            else:
                unique_trips.append((pred, objs[0]))

        # Build clause for this subject
        clauses = []
        for i, (pred, obj) in enumerate(unique_trips):
            func = phrase_funcs.get(pred)
            if func:
                if i == 0:
                    # First predicate - main clause
                    if pred == "nationality":
                        clauses.append(f"{subject} is {func(subject, obj)}")
                    elif pred in ["creator", "distributor", "broadcastedBy", "foundedBy"]:
                        clauses.append(f"{subject} {func(subject, obj)}")
                    else:
                        clauses.append(f"{subject} {func(subject, obj)}")
                else:
                    # Subsequent predicates - relative clauses
                    if pred in ["creator", "distributor", "broadcastedBy", "foundedBy"]:
                        clauses.append(f", {func(subject, obj)}")
                    else:
                        clauses.append(f", {func(subject, obj)}")

        if clauses:
            all_clauses.append("".join(clauses))

    # Combine all subject clauses into ONE complex sentence
    def clean_spaces(text):
        while "  " in text:
            text = text.replace("  ", " ")
        return text.strip()

    if len(all_clauses) == 0:
        return ""
    elif len(all_clauses) == 1:
        result = clean_spaces(all_clauses[0])
        if not result.endswith("."):
            result += "."
        return result
    else:
        # Connect all subjects into ONE complex sentence using relative clauses
        # Use "which" for non-main subjects to create proper flow
        result = all_clauses[0]
        for i, clause in enumerate(all_clauses[1:]):
            # Extract subject from clause to use in relative clause
            # Find the subject name at the beginning of the clause
            words = clause.split()
            if words:
                # Use "which" to connect related information
                result += f", which {clause.split(' ', 1)[1] if ' ' in clause else clause}"
        result = clean_spaces(result)
        if not result.endswith("."):
            result += "."
        return result

